global $wpdb;

// 1) Site-wide search for either email
$needles = ['niazbhatti8750@gmail.com', 'niaz@ideaditgital.services', 'niaz@ideadigital.services', 'niaz'];
$summary = [];
foreach ($needles as $n) {
    $like = '%' . $wpdb->esc_like($n) . '%';
    $live_pages_with_meta = $wpdb->get_results( $wpdb->prepare(
        "SELECT DISTINCT p.ID, p.post_title, p.post_type, p.post_status
         FROM {$wpdb->postmeta} pm
         JOIN {$wpdb->posts} p ON p.ID = pm.post_id
         WHERE pm.meta_value LIKE %s
           AND p.post_status = 'publish'
           AND p.post_type NOT IN ('revision')", $like
    ) );
    $rev_count = (int)$wpdb->get_var( $wpdb->prepare(
        "SELECT COUNT(*) FROM {$wpdb->postmeta} pm
         JOIN {$wpdb->posts} p ON p.ID = pm.post_id
         WHERE pm.meta_value LIKE %s AND p.post_type='revision'", $like
    ) );
    $opt = (int)$wpdb->get_var( $wpdb->prepare(
        "SELECT COUNT(*) FROM {$wpdb->options} WHERE option_value LIKE %s", $like
    ) );
    $summary[$n] = [
        'live_publish_hits' => array_map(fn($r)=>['ID'=>(int)$r->ID,'title'=>$r->post_title,'type'=>$r->post_type], $live_pages_with_meta),
        'revision_hits'     => $rev_count,
        'options_hits'      => $opt,
    ];
}

// 2) Current forms on Contact Us page 537
$forms = [];
$data = get_post_meta(537, '_elementor_data', true);
if ($data) {
    $arr = json_decode($data, true);
    $walk = function($nodes) use (&$walk, &$forms) {
        foreach ((array)$nodes as $node) {
            if (!is_array($node)) { continue; }
            $w = $node['widgetType'] ?? '';
            if ($w === 'form' || stripos($w, 'form') !== false) {
                $s = $node['settings'] ?? [];
                $forms[] = [
                    'widget_id'      => $node['id'] ?? null,
                    'widget_type'    => $w,
                    'form_name'      => $s['form_name'] ?? null,
                    'button_text'    => $s['button_text'] ?? null,
                    'email_to'       => $s['email_to'] ?? null,
                    'email_to_2'     => $s['email_to_2'] ?? null,
                    'email_subject'  => $s['email_subject'] ?? null,
                    'email_from'     => $s['email_from'] ?? null,
                    'email_from_name'=> $s['email_from_name'] ?? null,
                ];
            }
            if (!empty($node['elements'])) { $walk($node['elements']); }
        }
    };
    $walk($arr);
}

// 3) Last modified time of page 537
$p = get_post(537);

return [
    'page_537' => [
        'title' => $p ? $p->post_title : null,
        'status' => $p ? $p->post_status : null,
        'modified' => $p ? $p->post_modified : null,
        'modified_gmt' => $p ? $p->post_modified_gmt : null,
        'forms_current' => $forms,
    ],
    'sitewide_summary' => $summary,
];
